// Simple example; adjust weights as needed
const items = $input.items;
return items.map(item => {
  const data = item.json;
  const company = data.company || {};
  const metrics = company.metrics || {};
  const employeeCount = metrics.employees || 0;
  const alexa = metrics.alexa || 1000000;

  let score = 0;
  if (employeeCount > 50) score += 30;
  if (employeeCount > 200) score += 20;
  if (data.title && /director|vp|chief|head/i.test(data.title)) score += 20;
  if (alexa < 200000) score += 20;
  // Cap at 100
  if (score > 100) score = 100;

  return {
    json: {
      ...data,
      score,
      qualified: score >= 75
    }
  };
});

const item = $input.first().json;
const message = `🎯 *New Qualified Lead!*
Name: **${item.full_name}**
Company: **${item.company.name || item.company}**
Score: **${item.score}**`;
return [{ json: { message } }];
